class NetworkingLayer {
    let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func url(for endpoint: String) -> URL {
        switch environment {
        case .development:
            return URL(string: "https://dev-api.example.com/\(endpoint)")!
        case .staging:
            return URL(string: "https://stag-api.example.com/\(endpoint)")!
        case .production:
            return URL(string: "https://api.example.com/\(endpoint)")!
        }
    }
    
    func performGETRequest(for endpoint: String, completion: @escaping (Data?, Error?) -> Void) {
        guard let url = url(for: endpoint) else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }
            
            guard let data = data else { return }
            completion(data, nil)
        }.resume()
    }
    
    func performPOSTRequest(for endpoint: String, body: Data, completion: @escaping (Data?, Error?) -> Void) {
        guard let url = url(for: endpoint) else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = body
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(nil, error)
                return
            }
            
            guard let data = data else { return }
            completion(data, nil)
        }.resume()
    }
}

